pub type MCycles = u64; pub trait Bus { /// Reads a byte. TRIGGERS `io_cycle()` internally with the access /// cost (SLOW=8 / FAST=6 / XSLOW=12 mclk depending on the region). fn read(&mut self, addr: u32) -> u8; /// Writes a byte. May have side effects (MMIO registers). /// Also triggers `io_cycle()` with the access cost. fn write(&mut self, addr: u32, value: u8); /// **KEY PRIMITIVE FOR MID-INSTRUCTION ACCURACY.** /// Called by the CPU on every bus access (read, write, or internal /// cycle without an access). The bus uses it to immediately catch /// the PPU up, process HDMA, and test NMI/IRQ. /// /// This is what makes Mario Kart, F-Zero, and all games with /// HDMA/mid-frame effects correct. fn io_cycle(&mut self, mcycles: MCycles); /// Probes the interrupt lines after accumulation via io_cycle. fn nmi_pending(&self) -> bool; fn irq_pending(&self) -> bool;
} /// Trait for components stored behind the bus (PPU, DMA, etc.)
pub trait BusDevice { fn read(&mut self, addr: u32) -> u8; fn write(&mut self, addr: u32, value: u8); fn snapshot(&self) -> Vec<u8>; fn restore(&mut self, data: &[u8]) -> Result<(), SnapshotError>;
} Why io_cycle()? It is the primitive that separates a "moderately accurate" SNES emulator from a truly cycle-accurate one. Without it, the PPU is only caught up between CPU instructions — which misses HDMA effects, the exact timing of H/V IRQs, and the Mario Kart bugs. With it, every CPU memory access triggers a PPU catch-up to the exact cycle, which guarantees accuracy while staying zero-alloc in the hot loop.

